Let's start by creating the basic structure of the `MemTable` and `SSTable` classes within `lsm.py`. We'll focus on implementing the `put`, `get`, `delete`, `keys`, and initial flushing mechanism for now.

```json
{
  "name": "write_file",
  "arguments": {
    "path": "lsm.py",
    "content": "class MemTable:
    def __init__(self):
        self.data = {}

    def put(self, key, value):
        self.data[key] = value

    def get(self, key):
        return self.data.get(key, None)

    def delete(self, key):
        if key in self.data:
            del self.data[key]
        else:
            pass  # Handle missing key if needed

    def keys(self):
        return list(self.data.keys())

    def flush_to_file(self, filename):
        with open(filename, 'w') as f:
            for key, value in self.data.items():
                f.write(f'{key},{value}
')

class SSTable:
    def __init__(self, filename):
        self.filename = filename
        self.load_from_file()

    def load_from_file(self):
        self.data = {}
        with open(self.filename, 'r') as f:
            for line in f.readlines():
                key, value = line.strip().split(',')
                self.data[key] = value
"
  }
}
```
